import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatQty, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, monthStartEnd, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { PartnerDto, ReceivablePayableSummaryRow, ReceivablePayableDetailRow } from '../../../services/analytics/models';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const DEBT_OPTIONS = [{ value: '', label: 'Tất cả' }, { value: 'Receivable', label: 'Phải thu' }, { value: 'Payable', label: 'Phải trả' }];
const BaoCaoCongNoPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [tab, setTab] = useState<'summary'|'detail'>('summary');
  const [debtType, setDebtType] = useState('');
  const [partnerId, setPartnerId] = useState('');
  const [detailPartnerId, setDetailPartnerId] = useState('');
  const [partners, setPartners] = useState<PartnerDto[]>([]);
  const [summary, setSummary] = useState<ReceivablePayableSummaryRow[]>([]);
  const [detail, setDetail] = useState<ReceivablePayableDetailRow[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  React.useEffect(() => { let c=false; const t=setTimeout(()=>{ analyticsService.getPartners({ pageSize:500 }).then(d=>{if(!c)setPartners(d);}).catch(()=>{}); },0); return ()=>{c=true;clearTimeout(t);}; }, []);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ const p={ fromDate, toDate, debtType: debtType||undefined, partnerId: partnerId||undefined };
    (tab==='summary'? analyticsService.getReceivablePayableSummary(p): (detailPartnerId? analyticsService.getReceivablePayableDetail({...p, partnerId: detailPartnerId}): Promise.resolve([])))
      .then(d=>{ if(!c){ if(tab==='summary') setSummary(d as ReceivablePayableSummaryRow[]); else setDetail(d as ReceivablePayableDetailRow[]);} })
      .catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));})
      .finally(()=>{if(!c)setLoading(false);});
  },0); return ()=>{c=true;clearTimeout(t);}; }, [fromDate,toDate,debtType,partnerId,tab,detailPartnerId,dispatch, reloadKey]);
  const rows = tab==='summary'? summary : detail;
  const refresh = () => setReloadKey(k => k + 1);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-balance-scale" /> Báo cáo công nợ</h1><p className={styles.subtitle}>{fromDate} → {toDate}</p></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel(tab==='summary'?'/accounting/receivable-payable/summary/export-excel':'/accounting/receivable-payable/detail/export-excel',{fromDate,toDate,debtType:debtType||undefined,partnerId:(tab==='summary'?partnerId:detailPartnerId)||undefined},`CongNo-${fromDate}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.filtersBar} data-testid={`erp-bao-cao-cong-no-filters`}><DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v:DateRangeValue)=>{setFromDate(v.fromDate??'');setToDate(v.toDate??'');}} /><Select value={debtType} onChange={e=>setDebtType(e.target.value)} options={DEBT_OPTIONS} size="small" />
        {tab==='summary'?<Select value={partnerId} onChange={e=>setPartnerId(e.target.value)} options={[{value:'',label:'Tất cả ĐT'},...partners.map(p=>({value:p.id,label:p.name}))]} size="small" />:<Select value={detailPartnerId} onChange={e=>setDetailPartnerId(e.target.value)} options={[{value:'',label:'Chọn đối tác'},...partners.map(p=>({value:p.id,label:p.name}))]} size="small" />}</div>
      <div className={styles.tabs}><button type="button" className={tab==='summary'?styles.tabActive:styles.tab} onClick={()=>setTab('summary')}>Tổng hợp</button><button type="button" className={tab==='detail'?styles.tabActive:styles.tab} onClick={()=>setTab('detail')}>Chi tiết</button><ListSearchRefreshButtons testIdPrefix="erp-bao-cao-cong-no" onSearch={handleSearch} onRefresh={refresh} showSearch={false} /></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr>{tab==='summary'?<><th>Mã ĐT</th><th>Tên</th><th>TK</th><th className={styles.colRight}>Dư Nợ ĐK</th><th className={styles.colRight}>Dư Có ĐK</th><th className={styles.colRight}>PS Nợ</th><th className={styles.colRight}>PS Có</th><th className={styles.colRight}>Dư Nợ CK</th><th className={styles.colRight}>Dư Có CK</th></>:<><th>Ngày</th><th>Số CT</th><th>Loại</th><th>Diễn giải</th><th className={styles.colRight}>Nợ</th><th className={styles.colRight}>Có</th><th className={styles.colRight}>Số dư</th></>}</tr></thead><tbody>
        {tab==='summary'? summary.map((r,i)=>(<tr key={i}><td>{r.partnerCode}</td><td>{r.partnerName}</td><td>{r.accountCode}</td><td className={styles.colRight}>{formatVnd(r.openingDebit)}</td><td className={styles.colRight}>{formatVnd(r.openingCredit)}</td><td className={styles.colRight}>{formatVnd(r.arisingDebit)}</td><td className={styles.colRight}>{formatVnd(r.arisingCredit)}</td><td className={styles.colRight}>{formatVnd(r.closingDebit)}</td><td className={styles.colRight}>{formatVnd(r.closingCredit)}</td></tr>))
        : detail.map((r,i)=>(<tr key={i}><td>{formatDate(r.voucherDate)}</td><td>{r.voucherNumber}</td><td>{r.voucherType}</td><td>{r.description}</td><td className={styles.colRight}>{formatVnd(r.debitAmount)}</td><td className={styles.colRight}>{formatVnd(r.creditAmount)}</td><td className={styles.colRight}>{formatVnd(r.balance)}</td></tr>))}
        </tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoCongNoPage;
